// src/components/LiveMap.jsx
import React from 'react';

export default function LiveMap({ complaints = [], singlePin, singleCoords, height = '100%', onPinClick }) {
  // Base boundary anchors mapping precisely around the coordinates vector matrix of Nagpur Station
  const baseLat = 21.1522;
  const baseLng = 79.0882;

  return (
    <div style={{ height, width: '100%', background: '#0D1622', borderRadius: 12, border: '1px solid #243347', position: 'relative', overflow: 'hidden', boxShadow: 'inset 0 0 24px rgba(0,0,0,0.6)' }}>
      
      {/* 🗺️ NAGPUR RAILWAY STATION PLATFORMS & TRACKS VISUAL MATRIX LAYOUT */}
      <div style={{ position: 'absolute', inset: 0, opacity: 0.35, pointerEvents: 'none' }}>
        {/* Central Platform Tracks Blueprint Lines */}
        <div style={{ position: 'absolute', top: '35%', left: 0, right: 0, height: 2, background: '#00d2ff', boxShadow: '0 0 8px #00d2ff' }} />
        <div style={{ position: 'absolute', top: '45%', left: 0, right: 0, height: 2, background: '#00d2ff', boxShadow: '0 0 8px #00d2ff' }} />
        <div style={{ position: 'absolute', top: '55%', left: 0, right: 0, height: 2, background: '#38ef7d', boxShadow: '0 0 8px #38ef7d' }} />
        <div style={{ position: 'absolute', top: '65%', left: 0, right: 0, height: 2, background: '#38ef7d', boxShadow: '0 0 8px #38ef7d' }} />
        
        {/* Platform Blocks Overlays */}
        <div style={{ position: 'absolute', top: '38%', left: '15%', width: '70%', height: '5%', background: 'rgba(255,255,255,0.08)', border: '1px dashed rgba(0,210,255,0.4)', borderRadius: 4 }} />
        <div style={{ position: 'absolute', top: '48%', left: '10%', width: '75%', height: '5%', background: 'rgba(255,255,255,0.08)', border: '1px dashed rgba(0,210,255,0.4)', borderRadius: 4 }} />
        <div style={{ position: 'absolute', top: '58%', left: '20%', width: '65%', height: '5%', background: 'rgba(255,255,255,0.08)', border: '1px dashed rgba(56,239,125,0.4)', borderRadius: 4 }} />

        {/* Junction Yard Intersections Traces */}
        <div style={{ position: 'absolute', top: '25%', left: '10%', width: 2, height: '50%', background: 'rgba(0,210,255,0.2)', transform: 'rotate(45deg)' }} />
        <div style={{ position: 'absolute', top: '25%', right: '15%', width: 2, height: '50%', background: 'rgba(0,210,255,0.2)', transform: 'rotate(-45deg)' }} />
        
        {/* Textual Platform Layout Indicators */}
        <span style={{ position: 'absolute', top: '39%', left: '4%', fontSize: 8, color: '#00d2ff', fontFamily: 'monospace', opacity: 0.7 }}>PF 1-2</span>
        <span style={{ position: 'absolute', top: '49%', left: '4%', fontSize: 8, color: '#00d2ff', fontFamily: 'monospace', opacity: 0.7 }}>PF 3-4</span>
        <span style={{ position: 'absolute', top: '59%', left: '4%', fontSize: 8, color: '#38ef7d', fontFamily: 'monospace', opacity: 0.7 }}>PF 5-6</span>
      </div>

      {/* Background Structural Matrix Grid Design Overlays */}
      <div style={{ position: 'absolute', inset: 0, opacity: 0.12, background: 'linear-gradient(#00d2ff 1px, transparent 1px), linear-gradient(90deg, #00d2ff 1px, transparent 1px)', backgroundSize: '24px 24px' }} />
      
      {/* Dynamic Header Badge Overlay */}
      <div style={{ position: 'absolute', top: 10, left: 10, background: 'rgba(10,22,40,0.92)', color: '#00d2ff', padding: '5px 10px', borderRadius: 6, fontSize: 10, fontFamily: 'monospace', fontWeight: 'bold', zIndex: 10, border: '1px solid #1E3A5F', boxShadow: '0 2px 10px rgba(0,0,0,0.5)' }}>
        🛰️ NAGPUR JUNCTION LIVE PLATFORM MATRIX
      </div>

      <div style={{ width: '100%', height: '100%', position: 'relative' }}>
        {singlePin && singleCoords ? (
          <div style={{ position: 'absolute', left: '50%', top: '50%', transform: 'translate(-50%, -50%)', textAlign: 'center', zIndex: 5 }}>
            <div style={{ fontSize: 32, animation: 'bounce 1s infinite alternate', filter: 'drop-shadow(0 2px 6px rgba(0,0,0,0.6))' }}>📍</div>
            <div style={{ background: '#FF1744', color: '#fff', fontSize: 9, padding: '3px 6px', borderRadius: 4, whiteSpace: 'nowrap', fontWeight: 700, boxShadow: '0 2px 8px rgba(255,23,68,0.4)' }}>LIVE TARGET TRACK</div>
          </div>
        ) : (
          complaints.map((c, idx) => {
            const latDelta = (c.lat - baseLat) * 10000; 
            const lngDelta = (c.lng - baseLng) * 10000;

            // Positioning computation logic bound safely to canvas layout ratios
            const leftPct = 50 + (lngDelta * 3.8);
            const topPct = 50 - (latDelta * 3.8);

            return (
              <div 
                key={c.id || idx} 
                onClick={() => onPinClick && onPinClick(c)}
                style={{ 
                  position: 'absolute', 
                  left: `${Math.max(12, Math.min(leftPct, 88))}%`, 
                  top: `${Math.max(15, Math.min(topPct, 85))}%`, 
                  transform: 'translate(-50%, -50%)', 
                  cursor: 'pointer',
                  zIndex: 5,
                  transition: 'all 0.25s ease'
                }} 
                title={`${c.area} - ${c.gtype}`}
              >
                {/* Visual Pulse Wave Radar Ripple effect around live markers */}
                <div style={{ position: 'absolute', width: 28, height: 28, background: c.status === 'NEW' ? 'rgba(255,23,68,0.25)' : 'rgba(0,230,118,0.25)', borderRadius: '50%', transform: 'translate(-3px, -3px)', animation: 'ping 1.6s cubic-bezier(0, 0, 0.2, 1) infinite' }} />
                
                {/* FIXED BUG: Added c.emoji inside the template container layout so dots show up completely */}
                <div style={{ fontSize: 22, filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.5))', textAlign: 'center' }}>
                  {c.emoji || '🗑️'}
                </div>
                <div style={{ 
                  width: 8, 
                  height: 8, 
                  background: c.status === 'NEW' ? '#FF1744' : c.status === 'IN_PROGRESS' ? '#AA00FF' : '#00E676', 
                  borderRadius: '50%', 
                  border: '1.5px solid #fff', 
                  margin: '-1px auto 0 auto',
                  boxShadow: '0 2px 4px rgba(0,0,0,0.6)'
                }} />
              </div>
            );
          })
        )}
      </div>

      <style>{`
        @keyframes ping {
          0% { transform: scale(0.7); opacity: 1; }
          100% { transform: scale(2.2); opacity: 0; }
        }
        @keyframes bounce {
          from { transform: translate(-50%, -42%); }
          to { transform: translate(-50%, -58%); }
        }
      `}</style>
    </div>
  );
}
